/**
 * 부류/품목/품종 카탈로그 - 앱 전체의 단일 소스(SSOT).
 * 러버블 작물 아이콘 엑셀(대/중/소 분류)에서 자동 생성됨.
 *
 * 컴포넌트는 CATEGORIES/ITEMS를 직접 filter/find 하지 말고
 * 반드시 `src/lib/catalog-service.ts`의 함수를 사용할 것.
 */
import type { CropIconKey } from "@/lib/crop-icons";

export interface Variety {
  id: string;
  name: string;
  code: string;
}

export type PredictionStatus = "active" | "preparing" | "none";

export interface Prediction {
  supported: boolean;
  status: PredictionStatus;
}

export interface Item {
  id: string;
  name: string;
  emoji: string;
  iconKey: CropIconKey;
  categoryId: string;
  /** true일 때 소분류 없음 → 품종 선택 단계 생략 */
  hasNoVariety: boolean;
  varieties: Variety[];
  prediction: Prediction;
}

export interface Category {
  id: string;
  name: string;
  emoji: string;
  iconKey: CropIconKey;
}

